steps.script:
const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const org_id = cleanArg('{org_id}');
const campaign_id = cleanArg('{campaign_id}');
let org = org_id;
if (!org) {
  const m = location.pathname.match(/\/cm\/app\/(\d+)/);
  org = m ? m[1] : '';
}
if (!org) { return { error: 'could not resolve org_id from URL or param' }; }
let target;
if (campaign_id) {
  target = `https://app-ads.apple.com/cm/app/${org}/report/campaign/${encodeURIComponent(campaign_id)}`;
} else {
  target = `https://app-ads.apple.com/cm/app/${org}/report`;
}
setTimeout(() => window.location.assign(target), 0);
return { redirected: true, target, org, campaign_id: campaign_id || null };
